import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./studentDashboard.css";

export default function StudentDashboard() {
  const navigate = useNavigate();
  const token = localStorage.getItem("token");
  const [student, setStudent] = useState(null);
  const [mentors, setMentors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    if (!token) {
      navigate("/login");
      return;
    }
    const fetchData = async () => {
      try {
        setLoading(true);
        const s = await axios.get("http://localhost:5050/api/students/me", {
          headers: { Authorization: `Bearer ${token}` }
        });
        const m = await axios.get("http://localhost:5050/api/students/mentors", {
          headers: { Authorization: `Bearer ${token}` }
        });
        setStudent(s.data);
        setMentors(m.data);
        setError("");
      } catch (err) {
        console.error("Error fetching data:", err);
        setError(err.response?.data?.error || "Failed to load data");
        if (err.response?.status === 401 || err.response?.status === 403) {
          localStorage.clear();
          navigate("/login");
        }
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [token, navigate]);

  const logout = () => {
    localStorage.clear();
    navigate("/login");
  };

  if (loading) return <div className="student-dashboard"><p>Loading...</p></div>;
  if (error && !student) return <div className="student-dashboard"><p className="error-banner">{error}</p></div>;
  if (!student) return <div className="student-dashboard"><p>No student data found</p></div>;

  return (
    <div className="student-dashboard">
      <div className="dashboard-header">
        <h1>Hello, {student.studentname || student.Email}</h1>
        <button onClick={logout} className="logout-btn">Logout</button>
      </div>
      {error && <p className="error-banner">{error}</p>}
      <h2>Available Mentors</h2>
      {mentors.length === 0 ? (
        <p>No mentors available at the moment.</p>
      ) : (
        <div className="mentors-grid">
          {mentors.map(m => (
            <div key={m.sno} className="mentor-card">
              <h4>{m.facultyname}</h4>
              <p><strong>Specialization:</strong> {m.specialization}</p>
              <p><strong>Email:</strong> {m.Email}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
